INSERT INTO `exams` VALUES (1,'C','This exam is intended to assess knowledge of procedural programming using C. It includes hands-on problems involving pointers, recursion, and memory access. Questions range from basic syntax to memory layout and file operations in C.','2025-07-15','2025-08-30',20,1,'ONGOING','2025-07-15 14:58:50',20,3,'Programming'),(2,'Python','This exam evaluates your understanding of core Python syntax and problem-solving using Python. It includes MCQs, coding snippets, and case-based questions on real-world Python applications. Topics include OOP, functions, file handling, and control flow.','2025-07-15','2025-08-30',20,2,'ONGOING','2025-07-15 15:03:06',20,3,'Programming'),(4,'Java','This exam assesses the proficiency in Java programming fundamentals, including exception handling, OOP principles, and usage of collection APIs. It includes scenario-based coding questions and conceptual MCQs.','2025-07-15','2025-08-30',20,3,'ONGOING','2025-07-15 15:07:13',20,3,'Quantitative'),(5,'Aptitude','This exam assesses your potential to learn and perform specific tasks or skills. It measures cognitive abilities like logical reasoning, numerical ability, and verbal comprehension. Aptitude tests are often used in educational and employment settings to evaluate strengths, weaknesses, and suitability for various roles or fields.','2025-08-08','2025-09-06',20,4,'ONGOING','2025-08-08 11:20:59',NULL,3,'Programming'),(6,'Aptitude','Aptitude exam assesses your potential to learn and perform specific tasks or skills. It measures cognitive abilities like logical reasoning, numerical ability, and verbal comprehension. Aptitude tests are often used in educational and employment settings to evaluate strengths, weaknesses, and suitability for various roles or fields.','2025-08-08','2025-09-06',20,4,'ONGOING','2025-08-08 11:22:56',NULL,3,'Programming'),(7,'Aptitude','This exam assesses your potential to learn and perform specific tasks or skills. It measures cognitive abil