INSERT INTO `subjects` VALUES (1,'C Programming','C is a foundational, procedural programming language widely used for system-level programming, embedded systems, and OS development. It emphasizes performance and memory control.','2025-07-15 14:50:47',2,'ACTIVE'),(2,'Python Programming','Python is a high-level, versatile programming language known for its readability and vast library support. It is widely used for web development, data science, automation, AI/ML, and scripting.','2025-07-15 14:51:01',2,'ACTIVE'),(3,'Java Programming','Java is an object-oriented, class-based programming language designed for portability and performance. It is heavily used in enterprise software, Android development, and backend systems.Java is an object-oriented, class-based programming language designed for portability and performance. It is heavily used in enterprise software, Android development, and backend systems.','2025-07-15 14:51:16',2,'INACTIVE'),(4,'Quantitative','This subject focus on using numerical data and mathematical models and analyzing, and interpreting measurable information to identify patterns, trends, and relationships within data.','2025-08-08 10:34:34',2,'ACTIVE');
